import{_ as t,o as e,c as p,ag as o}from"./chunks/framework.DlAClNku.js";const r="/The-Mythical-Man-Month-zh/assets/fg3-1.CQP9w8lX.jpg",g=JSON.parse('{"title":"第 3 章 外科手术队伍（The Surgical Team）","description":"","frontmatter":{},"headers":[],"relativePath":"ch3.md","filePath":"ch3.md","lastUpdated":1777274400000}'),s={name:"ch3.md"};function l(n,a,i,h,c,u){return e(),p("div",null,[...a[0]||(a[0]=[o('<h1 id="第-3-章-外科手术队伍-the-surgical-team" tabindex="-1">第 3 章 外科手术队伍（The Surgical Team） <a class="header-anchor" href="#第-3-章-外科手术队伍-the-surgical-team" aria-label="Permalink to &quot;第 3 章 外科手术队伍（The Surgical Team）&quot;">​</a></h1><p>这些研究表明，效率高和效率低的实施者之间具体差别非常大，经常达到了数量级的水平。</p><p>——SACKMAN, ERIKSON 和 GRANT</p><p>These studies revealed large individual differences between high and low performers, often by an order of magnitude.</p><p>——SACKMAN, ERIKSON, AND GRANT</p><p>在计算机领域的会议上，常常听到年轻的软件经理宣称，他们宁要由头等人才组成的小型精干团队，也不要几百人的大型队伍——这里的&quot;人&quot;当然暗指平庸的程序员。说实话，我们也常常持同样的看法。</p><p>但这种想法，固然有其道理，却回避了一个真正艰难的问题——如何在合理的时间内构建大型系统？让我们来仔细审视这个问题的各个方面。</p><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>软件经理很早就意识到优秀程序员与普通程序员之间存在生产率差异，但实测数据揭示的差距仍令所有人震惊。Sackman、Erikson 和 Grant 对一组有经验的程序员进行研究，发现其中最好与最差的人在生产率上平均相差 10 倍，在运行速度和空间效率上则有高达 5 倍的惊人差距。简言之，一名年薪 20,000 美元的程序员，其生产率可能是年薪 10,000 美元者的 10 倍。数据还显示经验年限与实际表现之间并无相关性——对此我保留怀疑。</p><p>我一贯强调这样一个观点：需要相互协调沟通的人员数量，直接影响着开发成本——因为成本的主要构成是沟通本身，以及纠正沟通失误所造成的问题（即系统调试）。这也意味着，系统应该由尽可能少的人来开发。事实上，大量大型编程系统的经验表明，一拥而上的开发方式成本高、速度慢、质量差，交付的是在概念上无法整合的产品。OS/360、Exec 8、Scope 6600、Multics、TSS、SAFE……这份清单可以一直列下去。</p><p>结论很简单：如果一个 200 人的项目中有 25 位最能干、最有经验的项目经理，那就把其余 175 名程序员都解散，让这 25 位经理来写代码。</p><p>但且慢验证这个方案。一方面，这 25 人并不是理想的小型精干团队——这类团队的共识是不超过 10 人，而 25 人的规模已经需要至少两级管理层，约 5 名管理人员，以及额外的财务、人事、场地、文秘和机器运维支持。</p><p>另一方面，即使采用一拥而上的开发方式，200 人的队伍仍不足以构建真正大型的系统。以 OS/360 为例：巅峰时期有超过 1000 人在为它工作——程序员、文档编写人员、操作员、职员、秘书、管理人员、支持团队等。从 1963 年到 1966 年，设计、编码和文档工作耗费了大约 5000 人年。若人月真的可以等量互换，我们假设的这 200 人团队要达到相同水平，需要 25 年。</p><p>这就是小型精干团队概念上的根本困境：对于真正的大型系统，它太慢了。设想用一支 10 人的精干团队来完成 OS/360。假设他们个个出类拔萃，在编程和文档方面的生产率是普通程序员的 7 倍；再假设 OS/360 原有开发人员都是平庸之辈（实际上远非如此）；再假设团队规模缩小带来的沟通效率提升又贡献了 7 倍的生产率增益。那么：5000 /（10 × 7 × 7）= 10，他们需要整整 10 年来完成这 5000 人年的工作。一个产品在设计完成 10 年后才能问世，还会有人感兴趣吗？抑或早已被飞速发展的软件技术所淘汰？</p><p>这个两难困境是残酷的：从效率和概念完整性出发，最好由少数精干的人来设计和开发；但对于大型系统，又必须有大量人手，才能在时间上满足要求。如何调和这两者的矛盾？</p><h2 id="mills-的建议" tabindex="-1">Mills 的建议 <a class="header-anchor" href="#mills-的建议" aria-label="Permalink to &quot;Mills 的建议&quot;">​</a></h2><p>Harlan Mills 的提议给出了一个全新而富有创意的解决方案。Mills 建议大型项目的每个部分由一个团队负责，但这个团队应当像外科手术队伍一样组建，而非一拥而上。</p><p>具体而言，不是让每个成员各自承担问题的某一部分，而是由一个人主导整个问题的求解，其余人员则为他提供所需要的支持，以提升他的效率和生产力。</p><p>粗看之下，如果这一概念能够付诸实践，似乎确实能满足两方面的迫切需求。参与设计和开发的核心人员很少，其他人则提供各种配套支持。但这可行吗？谁来扮演编程团队中的麻醉师和护士？工作如何分工？让我们延续外科手术的比喻，设想这支队伍该如何组成。</p><p><strong>外科医生</strong>。Mills 称之为首席程序员。他亲自定义功能和性能规格说明，设计程序，编写源代码，测试，并撰写技术文档。他使用 PL/I 等结构化编程语言，拥有访问计算机系统的权限——该系统不仅支持测试，还存储程序的各个历史版本，允许便捷地更新文件，并为他的文档提供文本编辑功能。首席程序员需要极高的天赋、十年的经验，以及在应用数学、商业数据处理或其他相关领域深厚的系统与应用知识。</p><p><strong>副手</strong>。他是外科医生的替补，能胜任任何一部分工作，但经验相对较少。他的主要角色是首席程序员在设计上的思考伙伴、讨论者和评审人。首席程序员会与他深入探讨设计，但不受其建议的约束。副手常常代表本团队参与与其他团队的功能和接口讨论。他需要了解所有代码的细节，并研究各种设计方案的利弊。显然，他是首席程序员的安全保障。他也可能参与编码，但不对任何具体模块的开发负责。</p><p><strong>管理员</strong>。外科医生是技术上的老板，他必须在人员、薪酬等事务上有最终决定权，但绝不能把时间浪费在这些行政事务上。因此，他需要一位专职管理员来处理财务、人事、场地安排和设备，并充当与组织中其他管理层打交道的接口。Baker 建议，只有当项目涉及法律、合同、报告和财务需求时，管理员才需要全职投入；否则，一位管理员可以同时服务两个团队。</p><p><strong>编辑</strong>。为了最大限度地保证文档清晰，外科医生需要亲自起草——无论是内部文档还是外部文档都是如此。而编辑则根据他的草稿或口述，对内容进行梳理和重新组织，补充各类参考资料和参考书目，维护多个版本，并监督文档的生成流程。</p><p><strong>两名秘书</strong>。管理员和编辑各需要一名秘书。管理员的秘书负责项目的协调事务和非产品性文件。</p><p><strong>程序职员</strong>。他负责维护编程产品库中所有团队的技术记录。该职员具备文秘培训背景，承担机器码文件和可读文件的管理工作。</p><p>所有的计算机输入都汇集到他处，由他酌情记录或标注。输出列表提交给程序职员，由他归档并建立索引。此外，他负责将任何模型的最新运行情况记入状态日志，所有历史结果则按时间顺序存档保存。</p><p>Mills 这一构想的核心，是编程理念从&quot;个人艺术&quot;向&quot;公共实践&quot;的根本转变。它将所有的计算机运行结果和工作产物向所有团队成员公开，将程序和数据视为团队的共同财产，而非个人私有。</p><p>程序职员的专业化分工，将程序员从繁琐的记录工作中解放出来；与此同时，这些记录工作得到了系统整理，质量得到了保证，团队最宝贵的资产——工作产品——也因此得到了强化。这一概念显然是为批处理程序设计的。当使用交互式终端、特别是没有纸质输出时，程序职员的职责并未消失，只是有所调整——他记录团队程序与个人工作副本之间的变更，持续掌控所有程序的运行，并借助自己的交互式工具，维护产品日益增长的完整性与有效性。</p><p><strong>工具维护人员</strong>。如今已有大量文件编辑、文本编辑和交互式调试工具，团队几乎不再需要自己专属的机器和操作人员。但这些工具必须好用可靠，毫无疑问。外科医生是评判这些工具和服务是否合格的唯一权威。他需要一位工具维护人员，负责保障所有基础服务的可靠运行，并承担构建、维护和升级团队所需专用工具（特别是交互式计算机服务）的职责。即使已有非常出色的集中式服务，每个团队仍需配备自己的工具人员——因为他的职责是检视和确保自己所服务的那位&quot;外科医生&quot;所需工具的可用性。工具维护人员通常还需要开发一些实用程序，维护带索引的过程库和宏库。</p><p><strong>测试人员</strong>。外科医生需要大量合适的测试用例，以测试他所编写的代码片段，乃至整个程序。因此，测试人员既要为各项功能设计系统级测试用例，充当&quot;刁钻对手&quot;，又要为日常调试设计测试数据，充当得力助手。他还负责规划测试步骤，并搭建测试环境。</p><p><strong>语言专家</strong>。Algol 语言出现之后，人们逐渐认识到，大多数计算机项目中总有一两个热衷于深钻复杂编程语言的人。这类专家极为有用，很快人人都会去找他们请教。这些天才与外科医生不同——外科医生主要是系统设计者，关注的是系统的整体呈现；而语言专家则专注于寻找简洁、高效的语言用法，来解决那些复杂、晦涩或棘手的问题。他通常需要花几天时间对技术问题做深入研究。一般来说，一位语言专家可以同时服务两到三位外科医生。</p><p>以上就是按照外科手术队伍模式，对 10 人编程团队进行专业化角色分工的全貌。</p><h2 id="如何运作" tabindex="-1">如何运作 <a class="header-anchor" href="#如何运作" aria-label="Permalink to &quot;如何运作&quot;">​</a></h2><p>如此构成的开发团队，从多个方面满足了两难困境的需要。十个人中，七位专业人员专注于解决问题，而整个系统是由一个人（至多两个人）的思维产物，因此在客观上实现了概念的一致性。</p><p>值得特别留意的是，传统的两人团队与外科医生——副手架构之间有本质区别。在传统团队中，工作被划分，每人负责一部分的设计和实现；而在外科手术团队中，外科医生和副手共同掌握所有设计和全部代码。这不仅减少了空间分配、磁盘访问等方面的重复劳动，也保证了概念上的一致性。</p><p>其次，传统团队中人人平等，出现分歧时不可避免地需要讨论、妥协和让步。由于工作和资源被分割，意见不一会导致策略和接口上的不一致——比如谁的内存区域用作缓冲区——最终这些分歧还得被强行整合。而在外科手术团队中，不存在利益上的分歧，所有的意见分歧由外科医生一锤定音。这两处差异——不对问题进行分割，以及明确的上下级关系——使外科手术团队能够实现客观的一致性。</p><p>此外，团队其他成员的职能专业化，是高效运转的关键，它使成员之间得以采用极简的沟通模式。</p><p><img src="'+r+'" alt="10 人程序开发队伍的沟通模式"></p><blockquote><p>图 3.1：10 人程序开发队伍的沟通模式</p></blockquote><p>Baker 的论文提出了专职的小型测试团队。在实践中，这一模式运转如预期，效果良好。</p><h2 id="团队的扩建" tabindex="-1">团队的扩建 <a class="header-anchor" href="#团队的扩建" aria-label="Permalink to &quot;团队的扩建&quot;">​</a></h2><p>以上的分析固然不错，然而现在面临的问题是如何完成 5000 人年的项目，而不是 20 到 30 人年规模的系统。对于 10 人团队，无论如何组建，只要工作量在可控范围内，总是相当高效的。但是，面对需要几百人参与的大型任务时，外科手术团队的概念该如何推广应用？</p><p>扩建之所以可行，关键在于每个子模块的概念完整性得到了根本保障——负责设计决策的人员缩减到原来的七分之一甚至更少。因此，可以让 200 人去解决问题，但只需协调 20 人——那些&quot;外科医生&quot;的思路。</p><p>至于如何协调，仍需借助分解技术，后续章节将继续深入探讨。这里只需认识到：整个系统必须具备概念上的完整性，需要一位系统架构师从上至下地主导所有设计。要使工作易于管理，必须在体系结构设计与实现之间划出清晰的边界，系统架构师则须专注于体系结构本身，不为其他事务所分心。总体而言，这套角色分工和方法是切实可行的，在实践中具有相当高的效率。</p>',44)])])}const m=t(s,[["render",l]]);export{g as __pageData,m as default};
